-- Case 006: multi-table INSERT FIRST with conditional routing and nested SELECT
INSERT FIRST WHEN severity_score >= 90 AND is_replay = FALSE THEN INTO OPS.ALERT_CRITICAL(alert_id,tenant_id,event_id,severity_score,alert_payload,created_at) VALUES(UUID_STRING(),tenant_id,event_id,severity_score,alert_payload,CURRENT_TIMESTAMP()) WHEN severity_score >= 60 THEN INTO OPS.ALERT_WARNING(alert_id,tenant_id,event_id,severity_score,alert_payload,created_at) VALUES(UUID_STRING(),tenant_id,event_id,severity_score,alert_payload,CURRENT_TIMESTAMP()) ELSE INTO OPS.ALERT_INFO(alert_id,tenant_id,event_id,severity_score,alert_payload,created_at) VALUES(UUID_STRING(),tenant_id,event_id,severity_score,alert_payload,CURRENT_TIMESTAMP()) SELECT tenant_id,event_id,is_replay,severity_score,OBJECT_CONSTRUCT_KEEP_NULL( 'rule_id',rule_id, 'rule_name',rule_name, 'matched_terms',matched_terms, 'source',source_context, 'message',message) AS alert_payload FROM(SELECT e.payload:tenant::STRING AS tenant_id,e.event_id,COALESCE(e.payload:meta:is_replay::BOOLEAN,FALSE) AS is_replay,r.rule_id,r.rule_name,e.payload:message::STRING AS message,e.source_context,ARRAY_INTERSECTION(SPLIT(LOWER(e.payload:message::STRING), ' '),r.match_terms) AS matched_terms,LEAST(100,r.base_score + 5 * ARRAY_SIZE(matched_terms) + IFF(e.payload:meta:vip::BOOLEAN,10,0)) AS severity_score,ROW_NUMBER() OVER(PARTITION BY e.event_id,r.rule_id ORDER BY severity_score DESC,r.updated_at DESC) AS rule_rank FROM RAW.EVENT_LANDING AS e INNER JOIN OPS.ALERT_RULES AS r ON r.enabled AND e.payload:event_type::STRING = r.event_type WHERE e.loaded_at >= DATEADD( 'minute',-30,CURRENT_TIMESTAMP()) QUALIFY rule_rank = 1);
